import{_ as e,o as p,c as o,a4 as a}from"./chunks/framework.BDOgl-CJ.js";const d=JSON.parse('{"title":"为什么要记录思考","description":"","frontmatter":{},"headers":[],"relativePath":"thoughts/why-write.md","filePath":"thoughts/why-write.md","lastUpdated":1778596201000}'),r={name:"thoughts/why-write.md"};function s(h,t,n,_,i,u){return p(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="为什么要记录思考" tabindex="-1">为什么要记录思考 <a class="header-anchor" href="#为什么要记录思考" aria-label="Permalink to &quot;为什么要记录思考&quot;">​</a></h1><p><em>2026-05-12</em></p><hr><p>我发现自己有一个坏毛病：想清楚了就以为记住了。</p><p>一个问题翻来覆去想了好几天，某一个瞬间突然通了——觉得这辈子都不会忘。然后过了两个星期，那个感觉还在，但具体想清楚了什么，已经说不出来了。</p><p>留下来的只是一种模糊的&quot;我好像懂了&quot;，而不是真正的理解。</p><hr><p>所以我开始写。</p><p>不是为了给别人看，是为了逼自己把&quot;感觉上明白&quot;变成&quot;能说清楚&quot;。这两者之间的距离，往往比想象中大得多。</p><p>哲学书里有个说法让我印象很深：<strong>一个你说不清楚的想法，大概率你自己也没真正想清楚。</strong> 语言不只是表达思想的工具，语言本身就是思想的一部分。</p><p>写下来，就是在测试自己到底懂没懂。</p><hr><p>还有一个原因：我想看到自己的变化。</p><p>观点会变，认知会变，甚至人生阶段对同一件事的感受都会完全不同。现在写下来的东西，几年后再看，可能会觉得幼稚，也可能会觉得当时的自己更坦诚。</p><p>不管哪种，都比什么都没有强。</p><hr><p>所以这里会放一些我真正在想的东西。不追求完整，不追求正确，只追求诚实。</p><blockquote><p>思考是对自己诚实的练习。</p></blockquote>',18)])])}const l=e(r,[["render",s]]);export{d as __pageData,l as default};
